```typescript
type DiscountStrategy = (price: number, value: number) => number;

const discountStrategies: Record<string, DiscountStrategy> = {
  percentage: (price, value) => price * (1 - value / 100),
  fixed:      (price, value) => Math.max(0, price - value),
};

function applyDiscount(
  price: number,
  value: number,
  type: keyof typeof discountStrategies = "percentage"
): number {
  const strategy = discountStrategies[type];
  if (!strategy) throw new Error(`Unknown discount type: ${type}`);
  return strategy(price, value);
}
