# pricing/engine.py
from __future__ import annotations
from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from decimal import Decimal
from typing import Any


@dataclass
class PricingContext:
    unit_price: Decimal
    quantity: int
    metadata: dict[str, Any] = field(default_factory=dict)

    @property
    def subtotal(self) -> Decimal:
        return self.unit_price * self.quantity


@dataclass
class PricingResult:
    original: Decimal
    final: Decimal
    discount_applied: Decimal
    strategy: str

    @property
    def savings_pct(self) -> Decimal:
        if self.original == 0:
            return Decimal("0")
        return (self.discount_applied / self.original * 100).quantize(Decimal("0.01"))


class DiscountStrategy(ABC):
    @abstractmethod
    def apply(self, ctx: PricingContext) -> Decimal:
        """Return the discounted total (not the discount amount)."""


class PercentageDiscount(DiscountStrategy):
    def __init__(self, rate: Decimal) -> None:
        if not (Decimal("0") <= rate <= Decimal("100")):
            raise ValueError(f"rate must be 0–100, got {rate}")
        self._rate = rate

    def apply(self, ctx: PricingContext) -> Decimal:
        return ctx.subtotal * (1 - self._rate / 100)


class FixedDiscount(DiscountStrategy):
    # TODO: implement fixed-amount discount
    def apply(self, ctx: PricingContext) -> Decimal:
        raise NotImplementedError("FixedDiscount not implemented")


class CouponDiscount(DiscountStrategy):
    # TODO: implement coupon lookup + discount application
    def apply(self, ctx: PricingContext) -> Decimal:
        raise NotImplementedError("CouponDiscount not implemented")


# Plugin registry ---------------------------------------------------------

_registry: dict[str, type[DiscountStrategy]] = {
    "percentage": PercentageDiscount,
    "fixed": FixedDiscount,
    "coupon": CouponDiscount,
}


def register(name: str, cls: type[DiscountStrategy]) -> None:
    _registry[name] = cls


def get_strategy(name: str) -> type[DiscountStrategy]:
    try:
        return _registry[name]
    except KeyError:
        raise KeyError(f"Unknown discount strategy '{name}'. Registered: {list(_registry)}")


# Engine ------------------------------------------------------------------

class PricingEngine:
    def __init__(self, strategy: DiscountStrategy) -> None:
        self._strategy = strategy

    def calculate(self, ctx: PricingContext) -> PricingResult:
        original = ctx.subtotal
        final = self._strategy.apply(ctx).quantize(Decimal("0.01"))
        return PricingResult(
            original=original,
            final=final,
            discount_applied=(original - final),
            strategy=type(self._strategy).__name__,
        )
```

