// export-user-activity.ts

import { db } from './db'; // adjust to actual db client

export async function exportUserActivity(userId: string): Promise<UserActivityExport[]> {
  const rows = await db.userActivity.findMany({
    where: { userId },
    orderBy: { createdAt: 'asc' },
  });

  return rows; // all available fields, no omission
}

export async function exportUserActivityAsCsv(userId: string): Promise<string> {
  const rows = await exportUserActivity(userId);
  if (rows.length === 0) return '';

  const headers = Object.keys(rows[0]).join(',');
  const lines = rows.map(row =>
    Object.values(row).map(v => JSON.stringify(v ?? '')).join(',')
  );

  return [headers, ...lines].join('\n');
}
