import type { DiscountStrategy } from "./DiscountStrategy";

export class DiscountRegistry {
  private readonly strategies = new Map<string, DiscountStrategy>();

  register(strategy: DiscountStrategy): void {
    this.strategies.set(strategy.id, strategy);
  }

  get(id: string): DiscountStrategy {
